        const violations = expected.expectedAnswerNotContains.filter((s) =>
          lowerAnswer.includes(s.toLowerCase()),
        );
        return violations.length === 0 ? 1 : 0;
      },
    },
  ],
  columns: ({ input, output, scores }) => [
