+/** Known entity tables and the field that holds their display name. */
+const ENTITY_NAME_FIELDS: Record<string, string> = {
+  project: "name",
+  feature: "name",
+  person: "name",
+  task: "title",
+  decision: "summary",
+  question: "text",
+  observation: "text",
+};
